"""
Parameterized generator for GH1181_mlflow_21864.

Source PR:    https://github.com/mlflow/mlflow/pull/21864
Source Issue: N/A

Seed varies: renames 'adapters' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1181_mlflow_21864'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1181_mlflow_21864'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('adapters', 'adapters' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1181_mlflow_21864',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'mlflow/mlflow',
                "pr_number": 21864,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/mlflow/mlflow/pull/21864",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'mlflow/genai/discovery/utils.py': 'from __future__ import annotations\n\nimport functools\nimport logging\nimport threading\nimport time\nfrom collections import defaultdict\nfrom dataclasses import dataclass\nfrom typing import TYPE_CHECKING, Any\n\nimport pydantic\nimport requests\n\nimport mlflow\nfrom mlflow.entities.assessment import Feedback\nfrom mlflow.entities.trace import Trace\nfrom mlflow.gateway.config import EndpointType\nfrom mlflow.genai.discovery.constants import (\n    LLM_MAX_TOKENS,\n    NUM_RETRIES,\n    TRACE_CONTENT_TRUNCATION,\n)\nfrom mlflow.genai.discovery.entities import Issue, _ConversationAnalysis, _IdentifiedIssue\nfrom mlflow.genai.judges.adapters.litellm_adapter import (\n    _invoke_litellm,\n    _is_litellm_available,\n)\nfrom mlflow.genai.scorers.base import Scorer\nfrom mlflow.tracing.constant import TraceMetadataKey\nfrom mlflow.tracing.provider import trace_disabled\n\nif TYPE_CHECKING:\n    import litellm\n\n    from mlflow.gateway.schemas.chat import ResponsePayload\n\n_logger = logging.getLogger(__name__)\n\n\ndef get_session_id(trace: Trace) -> str | None:\n    return (trace.info.trace_metadata or {}).get(TraceMetadataKey.TRACE_SESSION)\n\n\ndef group_traces_by_session(\n    traces: list[Trace],\n) -> dict[str, list[Trace]]:\n    """\n    Group traces by session ID.\n\n    Traces without a session become standalone single-trace "sessions"\n    keyed by their trace_id. Each group is sorted by timestamp_ms.\n\n    Note: mlflow.genai.evaluation.session_utils has a similar function, but it\n    operates on EvalItem objects and drops traces without sessions. This version\n    works on raw Trace objects and keeps sessionless traces as standalone groups,\n    which is required for the discovery pipeline\'s frequency calculations.\n    """\n    groups: dict[str, list[Trace]] = defaultdict(list)\n    for trace in traces:\n        session_id = get_session_id(trace) or trace.info.trace_id\n        groups[session_id].append(trace)\n\n    for traces_in_group in groups.values():\n        traces_in_group.sort(key=lambda trace: trace.info.timestamp_ms)\n\n    return dict(groups)\n\n\nclass _TokenCounter:\n    """Thread-safe accumulator for LLM token usage across pipeline phases."""\n\n    def __init__(\n        self,\n        input_tokens: int = 0,\n        output_tokens: int = 0,\n        cost_usd: float = 0.0,\n        model: str | None = None,\n    ):\n        self._lock = threading.RLock()\n        self.input_tokens = input_tokens\n        self.output_tokens = output_tokens\n        self._cost_usd = cost_usd\n        self._cost_resolved = False\n        self._model = model\n\n    @property\n    def cost_usd(self) -> float | None:\n        """Return the total cost, falling back to the LiteLLM pricing API if needed."""\n        with self._lock:\n            if self._cost_usd == 0 and not self._cost_resolved:\n                total = self.input_tokens + self.output_tokens\n                if total > 0 and self._model:\n                    if cost := _lookup_model_cost(\n                        self._model, self.input_tokens, self.output_tokens\n                    ):\n                        self._cost_usd = cost\n                # Mark resolved once we\'ve attempted lookup with tokens present,\n                # or when there are no tokens yet (nothing to look up).\n                self._cost_resolved = total > 0 or not self._model\n            return self._cost_usd or None\n\n    def add_cost(self, cost: float) -> None:\n        with self._lock:\n            self._cost_usd += cost\n\n    def track(self, response: litellm.ModelResponse | ResponsePayload) -> None:\n        with self._lock:\n            if response.usage:\n                self.input_tokens += response.usage.prompt_tokens or 0\n                self.output_tokens += response.usage.completion_tokens or 0\n            if hidden := getattr(response, "_hidden_params", None):\n                if cost := hidden.get("response_cost"):\n                    self.add_cost(cost)\n\n    def to_dict(self) -> dict[str, int | float]:\n        result = {}\n        total = self.input_tokens + self.output_tokens\n        if total > 0:\n            result["input_tokens"] = self.input_tokens\n            result["output_tokens"] = self.output_tokens\n            result["total_tokens"] = total\n        if cost := self.cost_usd:\n            result["cost_usd"] = round(cost, 6)\n        return result\n\n\n@trace_disabled\ndef _call_llm(\n    model: str,\n    messages: list[dict[str, str]],\n    *,\n    json_mode: bool = False,\n    response_format: type[pydantic.BaseModel] | None = None,\n    token_counter: _TokenCounter | None = None,\n) -> Any:\n    if _is_litellm_available():\n        return _call_llm_via_litellm(\n            model,\n            messages,\n            json_mode=json_mode,\n            response_format=response_format,\n            token_counter=token_counter,\n        )\n    return _call_llm_via_gateway(\n        model,\n        messages,\n        json_mode=json_mode,\n        response_format=response_format,\n        token_counter=token_counter,\n    )\n\n\ndef _call_llm_via_litellm(\n    model: str,\n    messages: list[dict[str, str]],\n    *,\n    json_mode: bool = False,\n    response_format: type[pydantic.BaseModel] | None = None,\n    token_counter: _TokenCounter | None = None,\n) -> Any:\n    from mlflow.metrics.genai.model_utils import convert_mlflow_uri_to_litellm\n\n    use_format = response_format or ({"type": "json_object"} if json_mode else None)\n    response = _invoke_litellm(\n        litellm_model=convert_mlflow_uri_to_litellm(model),\n        messages=messages,\n        tools=[],\n        num_retries=NUM_RETRIES,\n        response_format=use_format,\n        include_response_format=use_format is not None,\n        inference_params={"max_completion_tokens": LLM_MAX_TOKENS},\n    )\n    if token_counter is not None:\n        token_counter.track(response)\n    return response\n\n\ndef _call_llm_via_gateway(\n    model: str,\n    messages: list[dict[str, str]],\n    *,\n    json_mode: bool = False,\n    response_format: type[pydantic.BaseModel] | None = None,\n    token_counter: _TokenCounter | None = None,\n) -> Any:\n    # Lightweight fallback for when LiteLLM is not installed. Only supports\n    # providers with MLflow gateway adapters (OpenAI, Anthropic, Gemini, Mistral).\n    # Known gaps vs the LiteLLM path: no drop_params\n    # (https://docs.litellm.ai/docs/completion/drop_params) - LiteLLM silently\n    # strips unsupported params (e.g. response_format) per model before sending\n    # the request, while this path sends them as-is. Not an issue for OpenAI\n    # and Anthropic which both support structured outputs. Also missing:\n    # no context window management and no per-request cost tracking.\n    from mlflow.metrics.genai.model_utils import (\n        _get_provider_instance,\n        _parse_model_uri,\n        _send_request,\n    )\n\n    provider_name, model_name = _parse_model_uri(model)\n    provider = _get_provider_instance(provider_name, model_name)\n\n    payload = {"messages": messages, "max_completion_tokens": LLM_MAX_TOKENS}\n    if response_format is not None:\n        payload["response_format"] = _pydantic_to_response_format(response_format)\n    elif json_mode:\n        payload["response_format"] = {"type": "json_object"}\n\n    chat_payload = provider.adapter_class.chat_to_model(payload, provider.config)\n\n    for attempt in range(NUM_RETRIES + 1):\n        try:\n            raw_response = _send_request(\n                endpoint=provider.get_endpoint_url(EndpointType.LLM_V1_CHAT),\n                headers=provider.headers,\n                payload=chat_payload,\n            )\n            break\n        except (\n            requests.exceptions.RequestException,\n            mlflow.exceptions.MlflowException,\n        ):\n            if attempt >= NUM_RETRIES:\n                raise\n            time.sleep(2**attempt)\n\n    response = provider.adapter_class.model_to_chat(raw_response, provider.config)\n    if token_counter is not None:\n        token_counter.track(response)\n    return response\n\n\ndef _pydantic_to_response_format(cls: type[pydantic.BaseModel]) -> dict[str, Any]:\n    return {\n        "type": "json_schema",\n        "json_schema": {\n            "name": cls.__name__,\n            "schema": cls.model_json_schema(),\n        },\n    }\n\n\n@dataclass(frozen=True)\nclass _ModelCost:\n    input_cost_per_token: float\n    output_cost_per_token: float\n\n    @classmethod\n    def from_dict(cls, data: dict[str, Any]) -> _ModelCost:\n        return cls(\n            input_cost_per_token=data.get("input_cost_per_token") or 0,\n            output_cost_per_token=data.get("output_cost_per_token") or 0,\n        )\n\n\n@functools.lru_cache(maxsize=64)\ndef _fetch_model_cost(model_name: str) -> _ModelCost | None:\n    # The API does a substring match (e.g. "gpt-5" also returns\n    # "ft:gpt-5-2025-09-15"), so we need to find the exact match.\n    from mlflow.utils.providers import _fetch_model_catalog_from_api\n\n    for entry in _fetch_model_catalog_from_api(model=model_name):\n        if entry.get("id") == model_name:\n            return _ModelCost.from_dict(entry)\n    return None\n\n\ndef _lookup_model_cost(model_uri: str, input_tokens: int, output_tokens: int) -> float | None:\n    from mlflow.metrics.genai.model_utils import _parse_model_uri\n\n    _, model_name = _parse_model_uri(model_uri)\n    if cost := _fetch_model_cost(model_name):\n        return input_tokens * cost.input_cost_per_token + output_tokens * cost.output_cost_per_token\n    return None\n\n\ndef build_summary(issues: list[Issue], total_traces: int) -> str:\n    if not issues:\n        return f"Analyzed {total_traces} traces. No issues found."\n\n    lines = [\n        f"Analyzed **{total_traces}** traces. Found **{len(issues)}** issues:\\n",\n    ]\n    for i, issue in enumerate(issues, 1):\n        root_causes = "; ".join(issue.root_causes) if issue.root_causes else "Unknown"\n        categories = ", ".join(issue.categories) if issue.categories else "None"\n        lines.append(\n            f"### {i}. {issue.name} (severity: {issue.severity})\\n\\n"\n            f"{issue.description}\\n\\n"\n            f"**Root causes:** {root_causes}\\n\\n"\n            f"**Categories:** {categories}\\n"\n        )\n    return "\\n".join(lines)\n\n\ndef log_discovery_artifacts(run_id: str, artifacts: dict[str, str]) -> None:\n    if not run_id:\n        return\n    client = mlflow.MlflowClient()\n    for filename, content in artifacts.items():\n        try:\n            client.log_text(run_id, content, filename)\n        except Exception:\n            _logger.warning("Failed to log %s to run %s", filename, run_id, exc_info=True)\n\n\n@trace_disabled\ndef verify_scorer(\n    scorer: Scorer,\n    trace: Trace,\n    session: list[Trace] | None = None,\n) -> None:\n    """\n    Verify a scorer works on a single trace (or session) before running the full pipeline.\n\n    Calls the scorer and checks that the returned Feedback has a non-null value.\n\n    Args:\n        scorer: The scorer to test.\n        trace: A trace to run the scorer on (used for trace-based scorers).\n        session: If provided, pass as ``session=`` to the scorer instead of ``trace=``.\n            Used for conversation-based scorers that require ``{{ conversation }}``.\n\n    Raises:\n        MlflowException: If the scorer produces no feedback or returns a null value.\n    """\n    try:\n        feedback = scorer(session=session) if session is not None else scorer(trace=trace)\n    except Exception as exc:\n        raise mlflow.exceptions.MlflowException(\n            f"Scorer \'{scorer.name}\' failed verification on trace {trace.info.trace_id}: {exc}"\n        ) from exc\n\n    if not isinstance(feedback, Feedback):\n        raise mlflow.exceptions.MlflowException(\n            f"Scorer \'{scorer.name}\' returned {type(feedback).__name__} instead of Feedback"\n        )\n    if feedback.value is None:\n        error = feedback.error_message or "unknown error (check model API logs)"\n        raise mlflow.exceptions.MlflowException(\n            f"Scorer \'{scorer.name}\' returned null value: {error}"\n        )\n\n\ndef collect_affected_trace_ids(\n    issue: _IdentifiedIssue,\n    analyses: list[_ConversationAnalysis],\n) -> list[str]:\n    """\n    Collect all affected trace IDs for an identified issue.\n\n    Args:\n        issue: The identified issue containing indices into the analyses list.\n        analyses: List of per-session analyses with affected trace IDs.\n\n    Returns:\n        A list of all trace IDs affected by this issue.\n    """\n    trace_ids = []\n    for idx in issue.example_indices:\n        if 0 <= idx < len(analyses):\n            trace_ids.extend(analyses[idx].affected_trace_ids)\n    return trace_ids\n\n\ndef format_trace_content(trace: Trace) -> str:\n    from mlflow.genai.discovery.extraction import extract_execution_path, extract_span_errors\n\n    parts = []\n    if request := trace.data.request:\n        parts.append(f"Input: {str(request)[:TRACE_CONTENT_TRUNCATION]}")\n    if response := trace.data.response:\n        parts.append(f"Output: {str(response)[:TRACE_CONTENT_TRUNCATION]}")\n    if (exec_path := extract_execution_path(trace)) and exec_path != "(no routing)":\n        parts.append(f"Execution path: {exec_path}")\n    if errors := extract_span_errors(trace):\n        parts.append(f"Errors: {errors}")\n    return "\\n".join(parts) if parts else "(trace content not available)"\n\n\ndef format_annotation_prompt(\n    issue: Issue,\n    trace_content: str,\n    triage_rationale: str,\n    categories: list[str] | None = None,\n) -> str:\n    prompt = (\n        f"=== ISSUE ===\\n"\n        f"Name: {issue.name}\\n"\n        f"Description: {issue.description}\\n"\n        f"Root causes: {\'; \'.join(issue.root_causes or [])}\\n\\n"\n        f"=== TRACE ===\\n"\n        f"{trace_content}\\n\\n"\n        f"=== TRIAGE JUDGE RATIONALE ===\\n"\n        f"{triage_rationale or \'(not available)\'}"\n    )\n    if categories:\n        prompt += (\n            f"\\n\\n=== RELEVANT CATEGORIES ===\\n"\n            f"{\', \'.join(categories)}\\n"\n            f"Reference these categories in your rationale where applicable."\n        )\n    return prompt\n',
            'tests/genai/discovery/test_utils.py': 'import time\nfrom unittest import mock\n\nimport pydantic\nimport pytest\n\nfrom mlflow.entities.issue import Issue, IssueStatus\nfrom mlflow.genai.discovery.entities import _ConversationAnalysis, _IdentifiedIssue\nfrom mlflow.genai.discovery.utils import (\n    _call_llm,\n    _lookup_model_cost,\n    _ModelCost,\n    _pydantic_to_response_format,\n    _TokenCounter,\n    build_summary,\n    collect_affected_trace_ids,\n    format_annotation_prompt,\n    format_trace_content,\n    get_session_id,\n    group_traces_by_session,\n    log_discovery_artifacts,\n)\nfrom mlflow.types.chat import ChatChoice, ChatCompletionResponse, ChatMessage, ChatUsage\n\n\ndef test_format_trace_content_includes_errors(make_trace):\n    trace = make_trace(error_span=True)\n    content = format_trace_content(trace)\n    assert "Errors:" in content\n    assert "Connection failed" in content\n\n\ndef test_format_trace_content_no_errors(make_trace):\n    trace = make_trace()\n    content = format_trace_content(trace)\n    assert "Errors:" not in content\n\n\ndef test_collect_affected_trace_ids_gathers_from_analyses():\n    analyses = [\n        _ConversationAnalysis(\n            full_rationale="r1", affected_trace_ids=["t1", "t2"], execution_path="p1"\n        ),\n        _ConversationAnalysis(full_rationale="r2", affected_trace_ids=["t3"], execution_path="p2"),\n    ]\n    issue = _IdentifiedIssue(\n        name="test",\n        description="d",\n        root_cause="rc",\n        severity="high",\n        example_indices=[0, 1],\n        categories=[],\n    )\n    result = collect_affected_trace_ids(issue, analyses)\n    assert result == ["t1", "t2", "t3"]\n\n\ndef test_collect_affected_trace_ids_skips_out_of_bounds():\n    analyses = [\n        _ConversationAnalysis(full_rationale="r1", affected_trace_ids=["t1"], execution_path="p1"),\n    ]\n    issue = _IdentifiedIssue(\n        name="test",\n        description="d",\n        root_cause="rc",\n        severity="high",\n        example_indices=[0, 5],\n        categories=[],\n    )\n    result = collect_affected_trace_ids(issue, analyses)\n    assert result == ["t1"]\n\n\n# ---- get_session_id ----\n\n\n@pytest.mark.parametrize(\n    ("session_id", "expected"),\n    [\n        ("sess-123", "sess-123"),\n        (None, None),\n    ],\n)\ndef test_get_session_id(make_trace, session_id, expected):\n    trace = make_trace(session_id=session_id)\n    assert get_session_id(trace) == expected\n\n\n# ---- log_discovery_artifacts ----\n\n\ndef test_log_discovery_artifacts_logs_text():\n    mock_client = mock.MagicMock()\n    with mock.patch("mlflow.MlflowClient", return_value=mock_client):\n        log_discovery_artifacts("run-1", {"file.txt": "content"})\n    mock_client.log_text.assert_called_once_with("run-1", "content", "file.txt")\n\n\ndef test_log_discovery_artifacts_skips_empty_run_id():\n    with mock.patch("mlflow.MlflowClient") as mock_client_cls:\n        log_discovery_artifacts("", {"file.txt": "content"})\n    mock_client_cls.assert_not_called()\n\n\ndef test_log_discovery_artifacts_handles_exception():\n    mock_client = mock.MagicMock()\n    mock_client.log_text.side_effect = Exception("fail")\n    with mock.patch("mlflow.MlflowClient", return_value=mock_client):\n        log_discovery_artifacts("run-1", {"file.txt": "content"})\n    mock_client.log_text.assert_called_once()\n\n\n# ---- format_annotation_prompt ----\n\n\ndef test_format_annotation_prompt():\n    issue = Issue(\n        issue_id="i1",\n        experiment_id="exp1",\n        name="Test Issue",\n        description="Test description",\n        status=IssueStatus.PENDING,\n        created_timestamp=0,\n        last_updated_timestamp=0,\n        root_causes=["cause1", "cause2"],\n    )\n    result = format_annotation_prompt(issue, "trace content here", "triage rationale here")\n    assert "=== ISSUE ===" in result\n    assert "Test Issue" in result\n    assert "Test description" in result\n    assert "cause1; cause2" in result\n    assert "=== TRACE ===" in result\n    assert "trace content here" in result\n    assert "=== TRIAGE JUDGE RATIONALE ===" in result\n    assert "triage rationale here" in result\n\n\n# ---- build_summary ----\n\n\ndef test_build_summary_no_issues():\n    result = build_summary([], 100)\n    assert result == "Analyzed 100 traces. No issues found."\n    assert not result.startswith("##")\n\n\ndef test_build_summary_with_issues():\n    issues = [\n        Issue(\n            issue_id="i1",\n            experiment_id="exp1",\n            name="Slow Response",\n            description="API responses are slow",\n            status=IssueStatus.PENDING,\n            created_timestamp=0,\n            last_updated_timestamp=0,\n            severity="high",\n            root_causes=["Database query optimization needed"],\n        ),\n        Issue(\n            issue_id="i2",\n            experiment_id="exp1",\n            name="Connection Errors",\n            description="Frequent connection timeouts",\n            status=IssueStatus.PENDING,\n            created_timestamp=0,\n            last_updated_timestamp=0,\n            severity="medium",\n            root_causes=["Network instability", "Upstream service issues"],\n        ),\n    ]\n    result = build_summary(issues, 50)\n    assert "Analyzed **50** traces" in result\n    assert "Found **2** issues" in result\n    assert not result.startswith("##")\n    assert "### 1. Slow Response" in result\n    assert "### 2. Connection Errors" in result\n    assert "Database query optimization needed" in result\n    assert "Network instability; Upstream service issues" in result\n\n\ndef test_token_counter_tracks_usage():\n    counter = _TokenCounter()\n    assert counter.input_tokens == 0\n    assert counter.output_tokens == 0\n    assert counter.cost_usd is None\n\n    mock_response = mock.MagicMock()\n    mock_response.usage = mock.MagicMock()\n    mock_response.usage.prompt_tokens = 100\n    mock_response.usage.completion_tokens = 50\n    mock_response._hidden_params = {"response_cost": 0.005}\n\n    counter.track(mock_response)\n\n    assert counter.input_tokens == 100\n    assert counter.output_tokens == 50\n    assert counter.cost_usd == 0.005\n\n\ndef test_token_counter_tracks_gateway_response_without_hidden_params():\n    counter = _TokenCounter(model="openai:/gpt-5-mini")\n    response = ChatCompletionResponse(\n        created=0,\n        model="gpt-5-mini",\n        choices=[ChatChoice(index=0, message=ChatMessage(role="assistant", content="hi"))],\n        usage=ChatUsage(prompt_tokens=200, completion_tokens=80, total_tokens=280),\n    )\n\n    counter.track(response)\n\n    assert counter.input_tokens == 200\n    assert counter.output_tokens == 80\n    assert counter._cost_usd == 0.0\n    assert counter._model == "openai:/gpt-5-mini"\n\n\ndef test_token_counter_to_dict_looks_up_cost_when_zero():\n    counter = _TokenCounter(input_tokens=100, output_tokens=50, model="openai:/gpt-5-mini")\n\n    with mock.patch(\n        "mlflow.genai.discovery.utils._lookup_model_cost",\n        return_value=0.0042,\n    ) as mock_lookup:\n        result = counter.to_dict()\n\n    mock_lookup.assert_called_once()\n    assert result["cost_usd"] == 0.0042\n    assert result["total_tokens"] == 150\n\n\ndef test_group_traces_by_session_groups_by_session_id(make_trace):\n    traces = [\n        make_trace(session_id="session-1"),\n        make_trace(session_id="session-1"),\n        make_trace(session_id="session-2"),\n    ]\n\n    result = group_traces_by_session(traces)\n\n    assert len(result) == 2\n    assert "session-1" in result\n    assert "session-2" in result\n    assert len(result["session-1"]) == 2\n    assert len(result["session-2"]) == 1\n\n\ndef test_group_traces_by_session_creates_standalone_groups_for_no_session(make_trace):\n    trace1 = make_trace(session_id=None)\n    trace2 = make_trace(session_id=None)\n    trace3 = make_trace(session_id="session-A")\n\n    traces = [trace1, trace2, trace3]\n    result = group_traces_by_session(traces)\n\n    assert len(result) == 3\n    assert trace1.info.trace_id in result\n    assert trace2.info.trace_id in result\n    assert "session-A" in result\n    assert len(result[trace1.info.trace_id]) == 1\n    assert len(result[trace2.info.trace_id]) == 1\n    assert len(result["session-A"]) == 1\n\n\ndef test_group_traces_by_session_sorts_by_timestamp(make_trace):\n    trace1 = make_trace(session_id="session-1")\n    time.sleep(0.01)\n    trace2 = make_trace(session_id="session-1")\n    time.sleep(0.01)\n    trace3 = make_trace(session_id="session-1")\n\n    traces = [trace3, trace1, trace2]\n\n    result = group_traces_by_session(traces)\n\n    session_traces = result["session-1"]\n    assert session_traces[0].info.trace_id == trace1.info.trace_id\n    assert session_traces[1].info.trace_id == trace2.info.trace_id\n    assert session_traces[2].info.trace_id == trace3.info.trace_id\n\n\ndef test_call_llm_uses_gateway_when_litellm_unavailable():\n    with (\n        mock.patch(\n            "mlflow.genai.discovery.utils._is_litellm_available", return_value=False\n        ) as mock_avail,\n        mock.patch(\n            "mlflow.genai.discovery.utils._call_llm_via_gateway",\n        ) as mock_gw,\n    ):\n        _call_llm("openai:/gpt-5-mini", [{"role": "user", "content": "hi"}])\n\n    mock_avail.assert_called_once()\n    mock_gw.assert_called_once()\n\n\ndef test_call_llm_uses_litellm_when_available():\n    with (\n        mock.patch(\n            "mlflow.genai.discovery.utils._is_litellm_available", return_value=True\n        ) as mock_avail,\n        mock.patch(\n            "mlflow.genai.discovery.utils._call_llm_via_litellm",\n        ) as mock_ll,\n    ):\n        _call_llm("openai:/gpt-5-mini", [{"role": "user", "content": "hi"}])\n\n    mock_avail.assert_called_once()\n    mock_ll.assert_called_once()\n\n\ndef test_pydantic_to_response_format():\n    class MySchema(pydantic.BaseModel):\n        name: str\n        score: int\n\n    result = _pydantic_to_response_format(MySchema)\n\n    assert result["type"] == "json_schema"\n    assert result["json_schema"]["name"] == "MySchema"\n    schema = result["json_schema"]["schema"]\n    assert "name" in schema["properties"]\n    assert "score" in schema["properties"]\n\n\ndef test_lookup_model_cost_returns_calculated_cost():\n    cost_info = _ModelCost(input_cost_per_token=0.00001, output_cost_per_token=0.00003)\n    with mock.patch(\n        "mlflow.genai.discovery.utils._fetch_model_cost", return_value=cost_info\n    ) as mock_fetch:\n        cost = _lookup_model_cost("openai:/gpt-5-mini", 1000, 500)\n\n    mock_fetch.assert_called_once()\n    assert cost == pytest.approx(1000 * 0.00001 + 500 * 0.00003)\n\n\ndef test_lookup_model_cost_returns_none_on_missing_model():\n    with mock.patch(\n        "mlflow.genai.discovery.utils._fetch_model_cost", return_value=None\n    ) as mock_fetch:\n        assert _lookup_model_cost("openai:/gpt-5-mini", 100, 50) is None\n\n    mock_fetch.assert_called_once()\n\n\ndef test_lookup_model_cost_returns_none_on_network_error():\n    with mock.patch(\n        "mlflow.genai.discovery.utils._fetch_model_cost", return_value=None\n    ) as mock_fetch:\n        assert _lookup_model_cost("openai:/gpt-5-mini", 100, 50) is None\n\n    mock_fetch.assert_called_once()\n',
        }
